    "cases.carbon_from_bim_6d.step.import-model.in.project": "प्रोजेक्ट रिकॉर्ड",
    "cases.carbon_from_bim_6d.step.import-model.out.elements": "सामग्री सहित एलिमेंट्स",
    "cases.carbon_from_bim_6d.step.import-model.out.quantities": "ज्योमेट्री से मात्राएं",
    "cases.carbon_from_bim_6d.step.import-model.title": "एक BIM मॉडल इम्पोर्ट करें",
    "cases.carbon_from_bim_6d.step.import-model.what": "BIM खोलें और इस काम के लिए बदला गया मॉडल इम्पोर्ट करें। कन्वर्जन पूरा होते ही, हर दीवार, स्लैब और कॉलम अपना सामग्री टैग और सॉलिड ज्योमेट्री से मापी गई मात्रा दोनों रखता है।",
    "cases.carbon_from_bim_6d.step.import-model.why": "पूरा फुटप्रिंट मॉडल से पढ़ा जाता है, इसलिए खराब इनपुट का मतलब खराब आउटपुट है। एक बदला गया मॉडल कार्बन मिलान को हाथ से टाइप किए गए आंकड़े की बजाय एक साफ सामग्री और असली मात्रा देता है।",
