    "demo_banner.modal_sample_data_label": "नमूना डेटा",
    "demo_banner.modal_sample_data_body": "यहाँ दिखाए गए सभी प्रोजेक्ट, BOQs और आंकड़े केवल प्रदर्शन के उद्देश्य से बनाया गया नमूना डेटा हैं। यहाँ कुछ भी वास्तविक प्रोजेक्ट डेटा नहीं है।",
    "demo_banner.modal_intro_before_vps": "आप इसका सार्वजनिक होस्ट किया गया डेमो देख रहे हैं",
    "demo_banner.modal_intro_runs_on": "यह चलता है एक",
